import java.util.ArrayList;
import java.util.List;

public class Main {
    static void dfs(List<List<Integer>> adjList, int current, boolean[] visited) {
        visited[current] = true;
        System.out.print(current + " ");

        for (int neighbor : adjList.get(current)) {
            if (!visited[neighbor]) {
                dfs(adjList, neighbor, visited);
            }
        }
    }

    public static void main(String[] args) {
        int n = 5;
        List<List<Integer>> adjList = new ArrayList<>();
        for (int i = 0; i < n; i++) adjList.add(new ArrayList<>());

        int[][] edges = {{0,1}, {0,2}, {1,3}, {2,4}};
        for (int[] e : edges) {
            adjList.get(e[0]).add(e[1]);
            adjList.get(e[1]).add(e[0]);
        }

        boolean[] visited = new boolean[n];
        dfs(adjList, 0, visited);
    }
}

import java.util.*;

public class Main {
    static void dfsIterative(List<List<Integer>> adjList, int start) {
        boolean[] visited = new boolean[adjList.size()];
        Deque<Integer> stack = new ArrayDeque<>();

        stack.push(start);

        while (!stack.isEmpty()) {
            int current = stack.pop();
            if (visited[current]) {
                continue; // already handled via another path
            }
            visited[current] = true;
            System.out.print(current + " ");

            for (int neighbor : adjList.get(current)) {
                if (!visited[neighbor]) {
                    stack.push(neighbor);
                }
            }
        }
    }

    public static void main(String[] args) {
        int n = 5;
        List<List<Integer>> adjList = new ArrayList<>();
        for (int i = 0; i < n; i++) adjList.add(new ArrayList<>());

        int[][] edges = {{0,1}, {0,2}, {1,3}, {2,4}};
        for (int[] e : edges) {
            adjList.get(e[0]).add(e[1]);
            adjList.get(e[1]).add(e[0]);
        }

        dfsIterative(adjList, 0);
    }
}

import java.util.ArrayList;
import java.util.List;

public class Main {
    static void dfs(List<List<Integer>> adjList, int current, boolean[] visited) {
        visited[current] = true;
        for (int neighbor : adjList.get(current)) {
            if (!visited[neighbor]) {
                dfs(adjList, neighbor, visited);
            }
        }
    }

    static int countComponents(List<List<Integer>> adjList) {
        boolean[] visited = new boolean[adjList.size()];
        int components = 0;

        for (int i = 0; i < adjList.size(); i++) {
            if (!visited[i]) {
                dfs(adjList, i, visited);
                components++;
            }
        }
        return components;
    }

    public static void main(String[] args) {
        int n = 6; // nodes 0-5
        List<List<Integer>> adjList = new ArrayList<>();
        for (int i = 0; i < n; i++) adjList.add(new ArrayList<>());

        int[][] edges = {{0,1}, {1,2}, {3,4}}; // node 5 is isolated
        for (int[] e : edges) {
            adjList.get(e[0]).add(e[1]);
            adjList.get(e[1]).add(e[0]);
        }

        System.out.println(countComponents(adjList));
    }
}

